const data = $input.first().json;
const ev   = $('PostgreSQL — Buscar Eventos').item.json;

console.log(`[Monitor] ${ev.name} (${ev.origin}->${ev.airport}) keys: ${Object.keys(data).join(', ')}`);
if (data.error) console.log(`[Monitor] ERRO: ${data.error}`);

const all = [...(data.best_flights || []), ...(data.other_flights || [])];

if (!all.length || data.error) {
  console.log(`[Monitor] Sem voos para ${ev.name}`);
  return [{ json: { skip: true, evento_name: ev.name } }];
}

const best = all.reduce((a, b) => (!a || b.price < a.price) ? b : a, null);
if (!best?.price) return [{ json: { skip: true, evento_name: ev.name } }];

const fl = best.flights || [];
console.log(`[Monitor] ${ev.name}: R$ ${best.price} (${fl[0]?.airline || 'N/D'})`);

return [{ json: {
  skip:        false,
  evento_id:   ev.id,
  evento_name: ev.name,
  airline:     fl[0]?.airline || 'N/D',
  price:       best.price,
  dep_time:    fl[0]?.departure_airport?.time?.slice(11,16) || '',
  arr_time:    (fl[fl.length-1] || fl[0])?.arrival_airport?.time?.slice(11,16) || '',
  stops:       (best.layovers || []).length,
  origin:      ev.origin,
  dest:        ev.airport,
  flight_date: ev.flight_date.toString().slice(0,10)
}}];
